import React, { useState } from "react";
import OdontogramaAvancado from "../components/OdontogramaAvancado";
import FormTratamento from "../components/FormTratamento";

export default function PaginaTratamento() {
  const [denteSelecionado, setDenteSelecionado] = useState("");
  const [regioesSelecionadas, setRegioesSelecionadas] = useState([]);
  // ...demais states

  return (
    <div>
      {/* Lista do dente selecionado (fora do odontograma) */}
      <div className="mb-4">
        {denteSelecionado && (
          <span className="inline-block px-3 py-1 rounded bg-blue-100 text-blue-700 text-sm font-semibold">
            Dente selecionado: {denteSelecionado}
          </span>
        )}
      </div>
      <FormTratamento
        denteSelecionado={denteSelecionado}
        regioesSelecionadas={regioesSelecionadas}
        // ...demais props
      />
      <OdontogramaAvancado
        denteSelecionado={denteSelecionado}
        setDenteSelecionado={setDenteSelecionado}
        regioesSelecionadas={regioesSelecionadas}
        setRegioesSelecionadas={setRegioesSelecionadas}
      />
      {/* ...demais conteúdos */}
    </div>
  );
}
